export const deleteCv = (
    cvId: string,
 options?: SecondParameter<typeof customInstance>,) => {
      
      
      return customInstance<ApiResponseVoid>(
      {url: `/api/candidates/cvs/${cvId}`, method: 'DELETE'
    },
      options);
    }
  


export const getDeleteCvMutationOptions = <TError = unknown,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof deleteCv>>, TError,{cvId: string}, TContext>, request?: SecondParameter<typeof customInstance>}
): UseMutationOptions<Awaited<ReturnType<typeof deleteCv>>, TError,{cvId: string}, TContext> => {

const mutationKey = ['deleteCv'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};

      


      const mutationFn: MutationFunction<Awaited<ReturnType<typeof deleteCv>>, {cvId: string}> = (props) => {
          const {cvId} = props ?? {};

          return  deleteCv(cvId,requestOptions)
        }

        


  return  { mutationFn, ...mutationOptions }}

    export type DeleteCvMutationResult = NonNullable<Awaited<ReturnType<typeof deleteCv>>>
    
    export type DeleteCvMutationError = unknown

    export const useDeleteCv = <TError = unknown,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof deleteCv>>, TError,{cvId: string}, TContext>, request?: SecondParameter<typeof customInstance>}
 , queryClient?: QueryClient): UseMutationResult<
        Awaited<ReturnType<typeof deleteCv>>,
        TError,
        {cvId: string},
        TContext
      > => {

      const mutationOptions = getDeleteCvMutationOptions(options);

      return useMutation(mutationOptions, queryClient);
    }
    